PROBLEMS = [
    {
        "id": "atm_pin_lockout",
        "title": "ATM PIN Lockout",
        "theme": "Banking",
        "difficulty": "Standard",
        "skill": "FSM + saturating counter + comparator",
        "statement": "Design an ATM PIN-entry controller.\n\nThe correct PIN is the fixed 4-digit sequence **1, 2, 3, 4** (each digit 0-9, presented one per cycle).\n\n**Behavior:**\n- Digits arrive one at a time on `digit` whenever `digit_valid` is high (one digit per pulse).\n- After 4 digits have been entered, compare them against the correct PIN.\n- If correct: pulse `access_granted` high for one cycle, and reset the fail counter.\n- If incorrect: increment an internal fail counter. After the **3rd consecutive** wrong attempt,\n  assert `locked_out` and ignore all further digit entry (even a correct PIN) until `admin_reset` is pulsed.\n- `admin_reset` clears the lock and fail counter at any time (synchronous).\n- `rst` is a synchronous reset that clears everything to the initial state.\n\nThis tests: state machine sequencing, a saturating fail-counter, and multi-signal comparison.",
        "interface": "module atm_pin (\n    input        clk,\n    input        rst,\n    input        admin_reset,\n    input  [3:0] digit,\n    input        digit_valid,\n    output reg   access_granted,\n    output reg   locked_out\n);",
        "starter": "module atm_pin (\n    input        clk,\n    input        rst,\n    input        admin_reset,\n    input  [3:0] digit,\n    input        digit_valid,\n    output reg   access_granted,\n    output reg   locked_out\n);\n    // TODO: implement the FSM\n    always @(posedge clk) begin\n        if (rst) begin\n            access_granted <= 0;\n            locked_out <= 0;\n        end\n        // TODO\n    end\nendmodule\n",
        "testbench": "`timescale 1ns/1ps\nmodule tb;\n    reg clk=0, rst=1, admin_reset=0, digit_valid=0;\n    reg [3:0] digit=0;\n    wire access_granted, locked_out;\n    integer errors = 0;\n\n    atm_pin dut(.clk(clk), .rst(rst), .admin_reset(admin_reset),\n                .digit(digit), .digit_valid(digit_valid),\n                .access_granted(access_granted), .locked_out(locked_out));\n\n    always #5 clk = ~clk;\n\n    task enter_digit(input [3:0] d);\n        begin\n            @(negedge clk);\n            digit = d; digit_valid = 1;\n            @(negedge clk);\n            digit_valid = 0;\n        end\n    endtask\n\n    task check(input cond, input [200*8:1] msg);\n        begin\n            if (!cond) begin\n                errors = errors + 1;\n                $display(\"FAIL: %s\", msg);\n            end\n        end\n    endtask\n\n    initial begin\n        @(negedge clk); rst = 0;\n\n        // Test A: correct PIN 1-2-3-4 grants access\n        enter_digit(1); enter_digit(2); enter_digit(3); enter_digit(4);\n        @(negedge clk);\n        check(access_granted == 1, \"correct PIN should grant access\");\n        check(locked_out == 0, \"should not be locked after success\");\n\n        // Test B: wrong PIN does not grant access, no lock yet (fail 1)\n        enter_digit(9); enter_digit(9); enter_digit(9); enter_digit(9);\n        @(negedge clk);\n        check(access_granted == 0, \"wrong PIN should not grant access\");\n        check(locked_out == 0, \"1st fail should not lock\");\n\n        // Test C: 2nd wrong attempt, still not locked\n        enter_digit(1); enter_digit(1); enter_digit(1); enter_digit(1);\n        @(negedge clk);\n        check(locked_out == 0, \"2nd fail should not lock\");\n\n        // Test D: 3rd wrong attempt -> locked out\n        enter_digit(5); enter_digit(5); enter_digit(5); enter_digit(5);\n        @(negedge clk);\n        check(locked_out == 1, \"3rd consecutive fail should lock\");\n\n        // Test E: while locked, correct PIN still denied\n        enter_digit(1); enter_digit(2); enter_digit(3); enter_digit(4);\n        @(negedge clk);\n        check(access_granted == 0, \"locked state must ignore correct PIN\");\n        check(locked_out == 1, \"should remain locked\");\n\n        // Test F: admin_reset clears lock\n        @(negedge clk); admin_reset = 1;\n        @(negedge clk); admin_reset = 0;\n        check(locked_out == 0, \"admin_reset should clear lock\");\n\n        // Test G: after admin_reset, correct PIN works again\n        enter_digit(1); enter_digit(2); enter_digit(3); enter_digit(4);\n        @(negedge clk);\n        check(access_granted == 1, \"PIN should work after admin_reset\");\n\n        if (errors == 0)\n            $display(\"RESULT:PASS\");\n        else\n            $display(\"RESULT:FAIL (%0d errors)\", errors);\n        $finish;\n    end\nendmodule\n",
        "hints": [
            "Use a small state register: IDLE -> collecting 4 digits -> CHECK -> IDLE/LOCK.",
            "Store each digit in its own register (or a shift register) as it arrives, and compare all 4 against the fixed PIN 1,2,3,4 once you have them.",
            "The fail counter should only increment on a *wrong* full attempt, and should reset to 0 on any correct attempt.",
            "Once locked, the FSM should ignore digit_valid entirely until admin_reset arrives."
        ]
    },
    {
        "id": "vault_sequence_detector",
        "title": "Wayne Vault Sequence Detector",
        "theme": "Superheroes",
        "difficulty": "Hard",
        "skill": "Overlapping pattern-matching FSM (classic hard interview question)",
        "statement": "Bruce Wayne's vault unlocks when it detects the exact bit pattern **1011** in a serial\ninput stream, **including overlapping occurrences**.\n\n**Behavior:**\n- On every clock edge, one new bit arrives on `bit_in`.\n- Whenever the most recent 4 bits received equal `1011`, pulse `unlock` high for exactly one cycle.\n- Overlaps count: e.g. the stream `1011011` contains a match ending at bit 4, and (because the tail of\n  that match can be reused as the start of the next) another match ending at bit 7.\n- `rst` synchronously resets the detector to its initial (no bits seen) state.\n\nThis is the classic \"overlapping sequence detector\" problem \u2014 a Moore FSM where a match can\nimmediately start reusing part of the previous match rather than needing to fully reset.",
        "interface": "module vault_detector (\n    input  clk,\n    input  rst,\n    input  bit_in,\n    output reg unlock\n);",
        "starter": "module vault_detector (\n    input  clk,\n    input  rst,\n    input  bit_in,\n    output reg unlock\n);\n    // TODO: implement overlapping sequence detector for pattern 1011\n    always @(posedge clk) begin\n        if (rst) unlock <= 0;\n        // TODO\n    end\nendmodule\n",
        "testbench": "`timescale 1ns/1ps\nmodule tb;\n    reg clk=0, rst=1, bit_in=0;\n    wire unlock;\n    integer errors = 0;\n    integer i;\n\n    vault_detector dut(.clk(clk), .rst(rst), .bit_in(bit_in), .unlock(unlock));\n\n    always #5 clk = ~clk;\n\n    // stream and expected unlock outputs, verified against a KMP automaton for pattern 1011\n    reg [12:0] stream   = 13'b1011011101011;\n    reg [12:0] expected = 13'b0001001000001;\n\n    task check_bit(input integer idx, input exp, input got);\n        begin\n            if (exp !== got) begin\n                errors = errors + 1;\n                $display(\"FAIL: bit %0d expected unlock=%0d got=%0d\", idx, exp, got);\n            end\n        end\n    endtask\n\n    initial begin\n        @(negedge clk); rst = 0;\n        for (i = 0; i < 13; i = i + 1) begin\n            @(negedge clk);\n            bit_in = stream[12-i];\n            @(posedge clk);\n            #1;\n            check_bit(i, expected[12-i], unlock);\n        end\n\n        if (errors == 0)\n            $display(\"RESULT:PASS\");\n        else\n            $display(\"RESULT:FAIL (%0d errors)\", errors);\n        $finish;\n    end\nendmodule\n",
        "hints": [
            "Think of states as 'longest prefix of 1011 matched so far ending at the current bit': 0, 1, 10, 101, 1011.",
            "From state 1011 (full match), don't reset to state 0 on the next bit \u2014 check whether the new bit lets you reuse part of the match (this is what makes it 'overlapping').",
            "This is exactly the KMP failure-function idea applied to hardware: build a small transition table for each state x each input bit.",
            "unlock should be asserted the cycle the 4th matching bit arrives, not a cycle later."
        ]
    },
    {
        "id": "traffic_light_priority",
        "title": "Intersection Controller with Pedestrian & Emergency Priority",
        "theme": "Real-world digital design",
        "difficulty": "Standard-Hard",
        "skill": "FSM + priority interrupts + latched request",
        "statement": "Design a traffic light controller for one direction of an intersection.\n\n**Normal cycle (in clock cycles, not seconds, for testability):** GREEN for 4 cycles -> YELLOW for 2\ncycles -> RED for 3 cycles -> back to GREEN.\n\n**Pedestrian request:** If `ped_request` is pulsed at any time while the light is GREEN or YELLOW, the\ncontroller must serve a 3-cycle pedestrian **walk phase** (`ped_walk` = 1, light held RED) immediately\nafter the current YELLOW phase ends, before returning to the normal RED phase.\n\n**Emergency override (highest priority):** Whenever `emergency` is asserted, the light must go to RED\nimmediately (regardless of current state) and stay RED as long as `emergency` is held. The moment\n`emergency` is released, the controller resumes with a fresh GREEN phase.\n\n`rst` synchronously resets to the start of a GREEN phase.\n\n`light` encoding: `00`=RED, `01`=YELLOW, `10`=GREEN.\n\nThis tests: multi-level priority arbitration (emergency > pedestrian > normal timing) combined with a\nlatched request that must survive across states until served.",
        "interface": "module traffic_light (\n    input        clk,\n    input        rst,\n    input        ped_request,\n    input        emergency,\n    output reg [1:0] light,\n    output reg   ped_walk\n);",
        "starter": "module traffic_light (\n    input        clk,\n    input        rst,\n    input        ped_request,\n    input        emergency,\n    output reg [1:0] light,\n    output reg   ped_walk\n);\n    // TODO: implement traffic light FSM with pedestrian request and emergency override\n    always @(posedge clk) begin\n        if (rst) begin\n            light <= 2'b10; // GREEN\n            ped_walk <= 0;\n        end\n        // TODO\n    end\nendmodule\n",
        "testbench": "`timescale 1ns/1ps\nmodule tb;\n    reg clk=0, rst=1, ped_request=0, emergency=0;\n    wire [1:0] light;\n    wire ped_walk;\n    integer errors = 0;\n    integer i;\n\n    traffic_light dut(.clk(clk), .rst(rst), .ped_request(ped_request),\n                       .emergency(emergency), .light(light), .ped_walk(ped_walk));\n\n    always #5 clk = ~clk;\n\n    // expected light (2 bits) and ped_walk per cycle, cycle 1..22, from verified python model\n    reg [1:0] exp_light [1:22];\n    reg       exp_pw    [1:22];\n\n    task check(input integer idx, input [1:0] elight, input epw);\n        begin\n            if (light !== elight) begin\n                errors = errors + 1;\n                $display(\"FAIL: cycle %0d expected light=%0d got=%0d\", idx, elight, light);\n            end\n            if (ped_walk !== epw) begin\n                errors = errors + 1;\n                $display(\"FAIL: cycle %0d expected ped_walk=%0d got=%0d\", idx, epw, ped_walk);\n            end\n        end\n    endtask\n\n    initial begin\n        // GREEN=2, YELLOW=1, RED=0\n        exp_light[1]=2; exp_pw[1]=0;\n        exp_light[2]=2; exp_pw[2]=0;\n        exp_light[3]=2; exp_pw[3]=0;\n        exp_light[4]=2; exp_pw[4]=0;\n        exp_light[5]=1; exp_pw[5]=0;\n        exp_light[6]=1; exp_pw[6]=0;\n        exp_light[7]=0; exp_pw[7]=1;\n        exp_light[8]=0; exp_pw[8]=1;\n        exp_light[9]=0; exp_pw[9]=1;\n        exp_light[10]=0; exp_pw[10]=0;\n        exp_light[11]=0; exp_pw[11]=0;\n        exp_light[12]=0; exp_pw[12]=0;\n        exp_light[13]=2; exp_pw[13]=0;\n        exp_light[14]=2; exp_pw[14]=0;\n        exp_light[15]=0; exp_pw[15]=0;\n        exp_light[16]=0; exp_pw[16]=0;\n        exp_light[17]=2; exp_pw[17]=0;\n        exp_light[18]=2; exp_pw[18]=0;\n        exp_light[19]=2; exp_pw[19]=0;\n        exp_light[20]=2; exp_pw[20]=0;\n        exp_light[21]=2; exp_pw[21]=0;\n        exp_light[22]=1; exp_pw[22]=0;\n\n        @(negedge clk); rst = 0;\n\n        for (i = 1; i <= 22; i = i + 1) begin\n            // set inputs for this cycle\n            ped_request = 1'b0;\n            emergency   = 1'b0;\n            if (i == 4) ped_request = 1'b1;\n            if (i == 15 || i == 16) emergency = 1'b1;\n\n            @(posedge clk);\n            #1;\n            check(i, exp_light[i], exp_pw[i]);\n        end\n\n        if (errors == 0)\n            $display(\"RESULT:PASS\");\n        else\n            $display(\"RESULT:FAIL (%0d errors)\", errors);\n        $finish;\n    end\nendmodule\n",
        "hints": [
            "Latch ped_request into a 'ped_pending' flip-flop the moment it arrives \u2014 don't act on the raw input signal directly, since it may only pulse for one cycle.",
            "emergency should override the case statement entirely at the top of your always block \u2014 it wins regardless of current state.",
            "Clear ped_pending only once the pedestrian walk phase has actually completed, not when you decide to serve it.",
            "Use a down-counter (or up-counter compared against a constant) for each phase's duration."
        ]
    },
    {
        "id": "infinity_stone_vending",
        "title": "Infinity Stone Vending Machine",
        "theme": "Superheroes",
        "difficulty": "Standard-Hard",
        "skill": "Accumulator + greedy change-making arithmetic",
        "statement": "A vending machine dispenses an Infinity Stone for **65 cents**. It accepts nickels (5c),\ndimes (10c), and quarters (25c), one coin per cycle via single-cycle pulses on `nickel_in`, `dime_in`,\n`quarter_in` (the testbench guarantees these are mutually exclusive and only asserted while `ready`\nis high).\n\n**Behavior:**\n- Accumulate credit as coins arrive.\n- The moment accumulated credit reaches or exceeds 65 cents: assert `dispense_item` for one cycle,\n  and compute change = credit - 65.\n- If there's change owed, dispense it using a **greedy algorithm** (as many quarters as possible, then\n  dimes, then nickels), pulsing `change_quarter` / `change_dime` / `change_nickel` for one cycle per\n  coin given as change.\n- Once change-making (if any) is complete, return to accepting coins (`ready` = 1) for the next\n  transaction, with credit reset to 0.\n- `ready` should be low while dispensing the item or making change, so the testbench (and a real user)\n  knows not to insert another coin mid-transaction.\n- `rst` synchronously resets to the initial ready-to-accept-coins state.\n\nThis tests: an accumulating register combined with combinational threshold detection (get the timing\nright \u2014 the check must include the coin being inserted *this* cycle, not lag a cycle behind), plus a\ngreedy change-making arithmetic sequence.",
        "interface": "module vending_machine (\n    input        clk,\n    input        rst,\n    input        nickel_in,\n    input        dime_in,\n    input        quarter_in,\n    output       ready,\n    output       dispense_item,\n    output       change_quarter,\n    output       change_dime,\n    output       change_nickel\n);",
        "starter": "module vending_machine (\n    input        clk,\n    input        rst,\n    input        nickel_in,\n    input        dime_in,\n    input        quarter_in,\n    output       ready,\n    output       dispense_item,\n    output       change_quarter,\n    output       change_dime,\n    output       change_nickel\n);\n    // TODO: implement vending machine with greedy change-making\n    assign ready = 1'b1;\n    assign dispense_item = 1'b0;\n    assign change_quarter = 1'b0;\n    assign change_dime = 1'b0;\n    assign change_nickel = 1'b0;\nendmodule\n",
        "testbench": "`timescale 1ns/1ps\nmodule tb;\n    reg clk=0, rst=1, nickel_in=0, dime_in=0, quarter_in=0;\n    wire ready, dispense_item, change_quarter, change_dime, change_nickel;\n    integer errors = 0;\n    integer i;\n\n    vending_machine dut(.clk(clk), .rst(rst), .nickel_in(nickel_in), .dime_in(dime_in),\n                         .quarter_in(quarter_in), .ready(ready), .dispense_item(dispense_item),\n                         .change_quarter(change_quarter), .change_dime(change_dime),\n                         .change_nickel(change_nickel));\n\n    always #5 clk = ~clk;\n\n    // cycle -> (quarter,dime,nickel) inserted THIS cycle\n    reg [2:0] q_seq [1:19];\n    reg [2:0] d_seq [1:19];\n    reg [2:0] n_seq [1:19];\n\n    // expected outputs per cycle: ready, dispense_item, change_quarter, change_dime, change_nickel\n    reg [4:0] exp [1:19];\n\n    task check(input integer idx);\n        begin\n            if (ready !== exp[idx][4]) begin errors=errors+1; $display(\"FAIL: cyc %0d ready exp=%0d got=%0d\", idx, exp[idx][4], ready); end\n            if (dispense_item !== exp[idx][3]) begin errors=errors+1; $display(\"FAIL: cyc %0d dispense_item exp=%0d got=%0d\", idx, exp[idx][3], dispense_item); end\n            if (change_quarter !== exp[idx][2]) begin errors=errors+1; $display(\"FAIL: cyc %0d change_quarter exp=%0d got=%0d\", idx, exp[idx][2], change_quarter); end\n            if (change_dime !== exp[idx][1]) begin errors=errors+1; $display(\"FAIL: cyc %0d change_dime exp=%0d got=%0d\", idx, exp[idx][1], change_dime); end\n            if (change_nickel !== exp[idx][0]) begin errors=errors+1; $display(\"FAIL: cyc %0d change_nickel exp=%0d got=%0d\", idx, exp[idx][0], change_nickel); end\n        end\n    endtask\n\n    initial begin\n        // Test A: 2 quarters + 1 dime + 1 nickel = 65 exactly, no change\n        // Test B: 3 quarters = 75, change = 1 dime\n        for (i = 1; i <= 19; i = i + 1) begin\n            q_seq[i]=0; d_seq[i]=0; n_seq[i]=0; exp[i]=5'b10000; // default ready=1, rest 0\n        end\n        q_seq[1]=1;\n        q_seq[2]=1;\n        d_seq[3]=1;\n        n_seq[4]=1;\n        // cycle4: threshold hit exactly on this insertion -> dispense fires same cycle\n        exp[4] = 5'b01000;\n        // cycles 5-12 idle back in collect (ready=1) -- defaults already set\n\n        q_seq[11]=1;\n        q_seq[12]=1;\n        q_seq[13]=1;\n        // cycle13: threshold hit -> dispense fires\n        exp[13] = 5'b01000;\n        // cycle14: change_dime=1\n        exp[14] = 5'b00010;\n        // cycles 15-19 back to ready (defaults)\n\n        @(negedge clk); rst = 0;\n\n        for (i = 1; i <= 19; i = i + 1) begin\n            quarter_in = q_seq[i];\n            dime_in    = d_seq[i];\n            nickel_in  = n_seq[i];\n            @(posedge clk);\n            #1;\n            check(i);\n        end\n\n        if (errors == 0)\n            $display(\"RESULT:PASS\");\n        else\n            $display(\"RESULT:FAIL (%0d errors)\", errors);\n        $finish;\n    end\nendmodule\n",
        "hints": [
            "Compute 'next_credit = credit + (coin value inserted this cycle)' combinationally, and compare next_credit against 65 \u2014 don't compare the old registered credit, or you'll be one coin late.",
            "The greedy change-making needs its own small state and a 'remaining' register that decreases by 25/10/5 each cycle until it hits 0.",
            "Watch out for non-blocking assignment lag: 'remaining <= remaining - 10; if (remaining == 0) ...' checks the OLD remaining. Compute (remaining - 10 == 0) instead if you want the transition to happen the same cycle the last coin is dispensed.",
            "ready is just a Moore output of your current state (are we in the coin-collecting state or not)."
        ]
    }
]
